function getOrder(tasks) {
    const taskIndices = tasks.map((_, i) => i).sort((a, b) => tasks[a][0] - tasks[b][0]);
    const minHeap = new MinHeap((a, b) => {
        if (a[1] === b[1]) return a[0] - b[0];
        return a[1] - b[1];
    });

    let time = 0;
    let taskIdx = 0;
    const result = [];

    while (taskIndices.length > 0) {
        while (taskIdx < taskIndices.length && tasks[taskIndices[taskIdx]][0] <= time) {
            const idx = taskIndices[taskIdx];
            minHeap.push([idx, tasks[idx][1]]);
            taskIdx++;
        }

        if (!minHeap.isEmpty()) {
            const [index, processingTime] = minHeap.pop();
            time += processingTime;
            result.push(index);
            taskIndices.splice(taskIndices.indexOf(index), 1);
        } else if (taskIdx < taskIndices.length) {
            time = Math.max(time, tasks[taskIndices[taskIdx]][0]);
        }
    }

    return result;
}

class MinHeap {
    constructor(comparator) {
        this.comparator = comparator;
        this.heap = [];
    }

    push(value) {
        this.heap.push(value);
        this.bubbleUp(this.heap.length - 1);
    }

    pop() {
        if (this.heap.length === 0) return undefined;
        const result = this.heap[0];
        const lastValue = this.heap.pop();
        if (this.heap.length > 0) {
            this.heap[0] = lastValue;
            this.bubbleDown(0);
        }
        return result;
    }

    bubbleUp(idx) {
        while (idx > 0) {
            const parentIdx = Math.floor((idx - 1) / 2);
            if (this.comparator(this.heap[idx], this.heap[parentIdx]) < 0) {
                const temp = this.heap[parentIdx];
                this.heap[parentIdx] = this.heap[idx];
                this.heap[idx] = temp;
                idx = parentIdx;
            } else {
                break;
            }
        }
    }

    bubbleDown(idx) {
        while (2 * idx + 1 < this.heap.length) {
            let childIdx = 2 * idx + 1;
            if (childIdx + 1 < this.heap.length && this.comparator(this.heap[childIdx], this.heap[childIdx + 1]) > 0) {
                childIdx++;
            }
            if (this.comparator(this.heap[idx], this.heap[childIdx]) > 0) {
                const temp = this.heap[childIdx];
                this.heap[childIdx] = this.heap[idx];
                this.heap[idx] = temp;
                idx = childIdx;
            } else {
                break;
            }
        }
    }

    isEmpty() {
        return this.heap.length === 0;
    }
}
